// tiffin-frontend/src/components/HomePage.jsx
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../Context/AuthContext';
import { getMealPlans, getTodayMeals } from '../services/api';

const HomePage = () => {
  const { user, isAuthenticated } = useAuth();
  const [mealPlans, setMealPlans] = useState([]);
  const [todayMeals, setTodayMeals] = useState([]);
  const [loadingPlans, setLoadingPlans] = useState(true);
  const [loadingMeals, setLoadingMeals] = useState(true);
  const [errorPlans, setErrorPlans] = useState(null);
  const [errorMeals, setErrorMeals] = useState(null);

  // Move fetchTodayMeals outside useEffect
  const fetchTodayMeals = async () => {
    try {
      const meals = await getTodayMeals();
      
      // Debug: Check what data is coming
      console.log('Today meals raw data:', meals);
      
      // Transform to ensure we have correct fields
      const transformedMeals = Array.isArray(meals) ? meals.map(meal => ({
        id: meal.id || meal.daily_menu_id || Math.random(),
        item_id: meal.item_id,
        meal_name: meal.meal_name || meal.item_name || meal.title,
        title: meal.meal_name || meal.item_name || meal.title, // For backward compatibility
        description: meal.description,
        calories: meal.calories,
        price: meal.price,
        image: meal.image || meal.image_url, // Map both image fields
        image_url: meal.image || meal.image_url, // Ensure both exist
        category: meal.category || meal.meal_type,
        available_quantity: meal.available_quantity
      })) : [];
      
      console.log('Transformed meals:', transformedMeals);
      setTodayMeals(transformedMeals);
    } catch (err) {
      console.error('Error fetching today meals:', err);
      setErrorMeals(err.message || 'Failed to load today\'s menu');
    } finally {
      setLoadingMeals(false);
    }
  };

  const fetchMealPlans = async () => {
    try {
      const plans = await getMealPlans();
      setMealPlans(plans.slice(0, 4)); // Show top 4 plans
    } catch (err) {
      setErrorPlans(err.message);
    } finally {
      setLoadingPlans(false);
    }
  };

  useEffect(() => {
    fetchMealPlans();
    fetchTodayMeals();
  }, []);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* SECTION 1: Hero Section */}
      <section className="relative bg-gradient-to-br from-red-500 to-red-700 text-white py-20 min-h-[70vh] flex items-center justify-center">
        <div className="absolute inset-0 bg-black opacity-20"></div>
        <div className="relative z-10 text-center px-4 max-w-4xl">
          <h1 className="text-4xl md:text-6xl font-bold mb-6 drop-shadow-lg">
            Fresh, Homemade Meals Delivered Daily
          </h1>
          <p className="text-lg md:text-xl mb-8 opacity-90">
            Enjoy nutritious, home-cooked meals tailored to your lifestyle. Subscribe today and never worry about cooking again.
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <Link
              to="/plans"
              className="bg-white text-red-600 px-8 py-3 rounded-full font-semibold hover:bg-gray-100 transition duration-300"
            >
              Browse Meal Plans
            </Link>
            <Link
              to="/menu"
              className="bg-transparent border-2 border-white text-white px-8 py-3 rounded-full font-semibold hover:bg-white hover:text-red-600 transition duration-300"
            >
              View Today's Menu
            </Link>
            {isAuthenticated && (
              <Link
                to="/dashboard"
                className="bg-red-800 text-white px-8 py-3 rounded-full font-semibold hover:bg-red-900 transition duration-300"
              >
                Go to Dashboard
              </Link>
            )}
          </div>
        </div>
      </section>

      {/* SECTION 2: Why Choose Us */}
      <section className="py-16 bg-white">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-800">
            Why Choose Us
          </h2>
          <div className="grid md:grid-cols-4 gap-8">
            <div className="text-center p-6 bg-gray-50 rounded-lg shadow-md hover:shadow-lg transition">
              <div className="text-5xl mb-4">🥗</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Healthy Homemade Meals</h3>
              <p className="text-gray-600">Freshly prepared with organic ingredients for optimal nutrition.</p>
            </div>
            <div className="text-center p-6 bg-gray-50 rounded-lg shadow-md hover:shadow-lg transition">
              <div className="text-5xl mb-4">⚙️</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Customizable Meal Plans</h3>
              <p className="text-gray-600">Tailor your meals to dietary preferences and restrictions.</p>
            </div>
            <div className="text-center p-6 bg-gray-50 rounded-lg shadow-md hover:shadow-lg transition">
              <div className="text-5xl mb-4">⏰</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">On-time Daily Delivery</h3>
              <p className="text-gray-600">Reliable delivery at your preferred time slot every day.</p>
            </div>
            <div className="text-center p-6 bg-gray-50 rounded-lg shadow-md hover:shadow-lg transition">
              <div className="text-5xl mb-4">💰</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Affordable Pricing</h3>
              <p className="text-gray-600">Competitive rates without compromising on quality.</p>
            </div>
          </div>
        </div>
      </section>

      {/* SECTION 3: Popular Meal Plans */}
      <section className="py-16 bg-gray-100">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-800">
            Popular Meal Plans
          </h2>
          {loadingPlans ? (
            <div className="text-center">
              <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-red-600"></div>
              <p className="mt-2 text-gray-600">Loading meal plans...</p>
            </div>
          ) : errorPlans ? (
            <div className="text-center text-red-600 bg-red-50 p-4 rounded-lg">
              <p>⚠️ {errorPlans}</p>
            </div>
          ) : (
            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
              {mealPlans.map((plan) => (
                <div key={plan.id} className="bg-white p-6 rounded-lg shadow-md hover:shadow-lg transition">
                  <h3 className="text-xl font-semibold mb-2 text-gray-800">{plan.name}</h3>
                  <p className="text-red-600 font-bold mb-2">₹{plan.price} per month</p>
                  <p className="text-gray-600 mb-4">{plan.description}</p>
                  <Link
                    to={`/plans/${plan.id}`}
                    className="bg-red-600 text-white px-4 py-2 rounded-full text-sm hover:bg-red-700 transition"
                  >
                    View Details
                  </Link>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* SECTION 4: Today's Menu Preview */}
      <section className="py-16 bg-white">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-800">
            Today's Menu Preview
          </h2>
          {loadingMeals ? (
            <div className="text-center">
              <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-red-600"></div>
              <p className="mt-2 text-gray-600">Loading today's menu...</p>
            </div>
          ) : errorMeals ? (
            <div className="text-center text-red-600 bg-red-50 p-4 rounded-lg">
              <p>⚠️ {errorMeals}</p>
              <button 
                onClick={fetchTodayMeals}
                className="mt-2 text-red-600 hover:text-red-800 underline"
              >
                Try Again
              </button>
            </div>
          ) : todayMeals.length === 0 ? (
            <div className="text-center text-gray-600 bg-gray-50 p-8 rounded-lg">
              <p className="text-lg">No meals available for today.</p>
              <p className="text-sm mt-2">Check back later or browse our meal plans!</p>
            </div>
          ) : (
            <>
              <div className="grid md:grid-cols-3 gap-8">
                {todayMeals.slice(0, 3).map((meal, index) => {
                  // Debug: Log each meal to see what fields are available
                  console.log(`Meal ${index}:`, meal);
                  
                  return (
                    <div key={meal.id || meal.item_id || index} className="bg-gray-50 p-6 rounded-lg shadow-md hover:shadow-lg transition-shadow">
                      {/* Image - FIXED with multiple field checks */}
                      <div className="w-full h-48 bg-gray-200 rounded-lg mb-4 overflow-hidden">
                        <img
                          src={meal.image || meal.image_url || meal.photo || meal.picture || '/default-meal.jpg'}
                          alt={meal.meal_name || meal.item_name || meal.title || `Meal ${index + 1}`}
                          className="w-full h-full object-cover hover:scale-105 transition-transform duration-300"
                          onError={(e) => {
                            e.target.src = 'https://images.unsplash.com/photo-1565958011703-44f9829ba187?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80';
                          }}
                        />
                      </div>
                      
                      {/* Meal Name - FIXED with multiple field checks */}
                      <h3 className="text-xl font-semibold mb-2 text-gray-800">
                        {meal.meal_name || meal.item_name || meal.title || `Meal ${index + 1}`}
                      </h3>
                      
                      {/* Calories - FIXED */}
                      <p className="text-gray-600 mb-2">
                        <span className="font-medium">🔥 {meal.calories || 'N/A'} calories</span>
                      </p>
                      
                      {/* Price - FIXED */}
                      {meal.price && (
                        <p className="text-red-600 font-bold">₹{meal.price}</p>
                      )}
                      
                      {/* Description if available */}
                      {meal.description && (
                        <p className="text-gray-500 text-sm mt-2 line-clamp-2">
                          {meal.description}
                        </p>
                      )}
                    </div>
                  );
                })}
              </div>
              
              {/* Show more meals button if available */}
              {todayMeals.length > 3 && (
                <div className="text-center mt-6">
                  <p className="text-gray-600 mb-2">
                    + {todayMeals.length - 3} more items available
                  </p>
                </div>
              )}
            </>
          )}
          <div className="text-center mt-8">
            <Link
              to="/menu"
              className="inline-flex items-center bg-red-600 text-white px-8 py-3 rounded-full font-semibold hover:bg-red-700 transition-all hover:scale-105"
            >
              <span>View Full Menu</span>
              <svg className="w-5 h-5 ml-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
              </svg>
            </Link>
          </div>
        </div>
      </section>

      {/* SECTION 5: How It Works */}
      <section className="py-16 bg-gray-100">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-800">
            How It Works
          </h2>
          <div className="grid md:grid-cols-4 gap-8 text-center">
            <div className="p-6">
              <div className="text-6xl mb-4">📋</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Choose Your Plan</h3>
              <p className="text-gray-600">Select from our variety of meal plans that suit your needs.</p>
            </div>
            <div className="p-6">
              <div className="text-6xl mb-4">📅</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Select Start Date</h3>
              <p className="text-gray-600">Pick a convenient start date for your subscription.</p>
            </div>
            <div className="p-6">
              <div className="text-6xl mb-4">🚚</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Daily Fresh Delivery</h3>
              <p className="text-gray-600">Receive hot, fresh meals delivered to your doorstep daily.</p>
            </div>
            <div className="p-6">
              <div className="text-6xl mb-4">📊</div>
              <h3 className="text-xl font-semibold mb-2 text-gray-800">Track Everything on Dashboard</h3>
              <p className="text-gray-600">Monitor your deliveries, payments, and feedback in real-time.</p>
            </div>
          </div>
        </div>
      </section>

      {/* SECTION 6: Customer Testimonials */}
      <section className="py-16 bg-white">
        <div className="max-w-6xl mx-auto px-4">
          <h2 className="text-3xl md:text-4xl font-bold text-center mb-12 text-gray-800">
            Customer Testimonials
          </h2>
          <div className="grid md:grid-cols-3 gap-8">
            <div className="bg-gray-50 p-6 rounded-lg shadow-md">
              <div className="flex mb-4">
                {[...Array(5)].map((_, i) => (
                  <span key={i} className="text-yellow-400">⭐</span>
                ))}
              </div>
              <p className="text-gray-700 mb-4">"Amazing service! The meals are always fresh and delicious."</p>
              <h4 className="font-semibold text-gray-800">Priya Sharma</h4>
            </div>
            <div className="bg-gray-50 p-6 rounded-lg shadow-md">
              <div className="flex mb-4">
                {[...Array(5)].map((_, i) => (
                  <span key={i} className="text-yellow-400">⭐</span>
                ))}
              </div>
              <p className="text-gray-700 mb-4">"Convenient and affordable. Perfect for busy professionals."</p>
              <h4 className="font-semibold text-gray-800">Rahul Verma</h4>
            </div>
            <div className="bg-gray-50 p-6 rounded-lg shadow-md">
              <div className="flex mb-4">
                {[...Array(5)].map((_, i) => (
                  <span key={i} className="text-yellow-400">⭐</span>
                ))}
              </div>
              <p className="text-gray-700 mb-4">"Great variety and excellent customer support."</p>
              <h4 className="font-semibold text-gray-800">Anjali Gupta</h4>
            </div>
          </div>
        </div>
      </section>

      {/* SECTION 7: Call to Action Footer */}
      <section className="py-16 bg-red-600 text-white">
        <div className="max-w-4xl mx-auto text-center px-4">
          <h2 className="text-3xl md:text-4xl font-bold mb-6">
            Start Your Meal Subscription Today!
          </h2>
          <p className="text-lg mb-8 opacity-90">
            Join thousands of satisfied customers enjoying healthy, home-cooked meals.
          </p>
          {isAuthenticated ? (
            <Link
              to="/dashboard"
              className="bg-white text-red-600 px-8 py-3 rounded-full font-semibold hover:bg-gray-100 transition duration-300"
            >
              Go to Dashboard
            </Link>
          ) : (
            <Link
              to="/plans"
              className="bg-white text-red-600 px-8 py-3 rounded-full font-semibold hover:bg-gray-100 transition duration-300"
            >
              Browse Plans
            </Link>
          )}
        </div>
      </section>
    </div>
  );
};

export default HomePage;
